class Personnage:
    def __init__(self, nom, vie):
        self.nom = nom
        self.vie = vie

class Dragon(Personnage):
    def __init__(self, nom, vie, couleur_feu):
        super().__init__(nom, vie)
        self.couleur_feu = couleur_feu

    def crache_feu(self):
        return f"{self.nom} crache du feu {self.couleur_feu} !"

# Test
dragon = Dragon("Smaug", 1000, "rouge")
print(dragon.crache_feu())

def nombres_puissants(max):
    for i in range(1, max + 1):
        yield i ** i

# Test
for nombre in nombres_puissants(5):
    print(nombre)

def cree_classe_automatique(nom, methodes):
    return type(nom, (object,), methodes)

# Test
